import { create } from 'zustand';

export type UpgradeOption = 'attack_speed' | 'attack_damage' | 'move_speed';

interface GameState {
  status: 'menu' | 'playing' | 'paused' | 'upgrading' | 'gameover' | 'victory';
  score: number;
  timeRemaining: number;
  level: number;
  exp: number;
  maxExp: number;

  // 玩家状态
  playerHp: number;
  playerMaxHp: number;
  attackSpeed: number; // 攻击间隔(ms)
  attackDamage: number;
  moveSpeed: number;

  // 供升级使用
  pendingUpgrades: UpgradeOption[];

  // Actions
  setStatus: (status: GameState['status']) => void;
  updateTime: (time: number) => void;
  addExp: (amount: number) => void;
  takeDamage: (amount: number) => void;
  applyUpgrade: (type: UpgradeOption) => void;
  setPendingUpgrades: (upgrades: UpgradeOption[]) => void;
  resetGame: () => void;
}

const INITIAL_STATE = {
  status: 'menu' as const,
  score: 0,
  timeRemaining: 180,
  level: 1,
  exp: 0,
  maxExp: 100, // 初始所需经验

  playerHp: 100,
  playerMaxHp: 100,
  attackSpeed: 1000, // 初始 1 次/秒
  attackDamage: 10,
  moveSpeed: 150,

  pendingUpgrades: []
};

export const useGameStore = create<GameState>((set, get) => ({
  ...INITIAL_STATE,

  setStatus: (status) => set({ status }),
  updateTime: (timeRemaining) => set({ timeRemaining }),

  addExp: (amount) => set((state) => {
    let newExp = state.exp + amount;
    let newLevel = state.level;
    let newMaxExp = state.maxExp;
    let triggerUpgrade = false;

    // 简化处理：一次最多升一级，多余经验保留
    if (newExp >= newMaxExp) {
      newExp -= newMaxExp;
      newLevel += 1;
      newMaxExp = Math.floor(newMaxExp * 1.5); // 经验曲线
      triggerUpgrade = true;
    }

    // 注意：Zustand store 不直接修改 pendingUpgrades，由 Phaser Scene 监听等级变化或触发事件，这里仅修改状态。
    // 但是为了方便在 React 侧直接触发，这里也可以先存状态。
    return { exp: newExp, level: newLevel, maxExp: newMaxExp, status: triggerUpgrade ? 'upgrading' : state.status };
  }),

  takeDamage: (amount) => set((state) => {
    const newHp = Math.max(0, state.playerHp - amount);
    if (newHp === 0 && state.status === 'playing') {
      return { playerHp: newHp, status: 'gameover' };
    }
    return { playerHp: newHp };
  }),

  setPendingUpgrades: (pendingUpgrades) => set({ pendingUpgrades }),

  applyUpgrade: (type) => set((state) => {
    const updates: Partial<GameState> = { status: 'playing' };
    switch (type) {
      case 'attack_speed':
        updates.attackSpeed = Math.max(200, state.attackSpeed * 0.8); // 攻速提升，攻击间隔减少 20%
        break;
      case 'attack_damage':
        updates.attackDamage = state.attackDamage + 5; // 每次加 5 点固定伤害
        break;
      case 'move_speed':
        updates.moveSpeed = state.moveSpeed * 1.1; // 移速提升 10%
        break;
    }
    return updates;
  }),

  resetGame: () => set({ ...INITIAL_STATE, status: 'playing' })
}));

import Phaser from 'phaser';

export const EventBus = new Phaser.Events.EventEmitter();

export const GameEvents = {
  SCENE_READY: 'scene-ready',
  START_GAME: 'start-game',
  GAME_OVER: 'game-over',
  VICTORY: 'victory',
  TRIGGER_UPGRADE: 'trigger-upgrade',
  UPGRADE_APPLIED: 'upgrade-applied',
  RESTART_GAME: 'restart-game'
};

import { Boot } from './scenes/Boot';
import { Preloader } from './scenes/Preloader';
import { MainGame } from './scenes/MainGame';

export const GameConfig: Phaser.Types.Core.GameConfig = {
    type: Phaser.AUTO,
    parent: 'game-container',
    width: 800,
    height: 600,
    backgroundColor: '#FDFBF7', // 奶油白
    physics: {
        default: 'arcade',
        arcade: {
            gravity: { x: 0, y: 0 },
            debug: false
        }
    },
    scale: {
        mode: Phaser.Scale.FIT,
        autoCenter: Phaser.Scale.CENTER_BOTH
    },
    scene: [Boot, Preloader, MainGame]
};

export const createGame = () => {
    return new Phaser.Game(GameConfig);
};

// Constants
export const CONSTANTS = {
  GAME_DURATION: 180, // 180 秒存活
  EXP_GEM_BASE_VALUE: 10,
  ENEMY_SPAWN_RATE_BASE: 1000, // 基础生成间隔1秒
};

import { useEffect, useRef } from 'react';
import Phaser from 'phaser';
import { createGame } from './game/main';
import { useGameStore } from './store/gameStore';
import { EventBus, GameEvents } from './game/EventBus';

// Components
import HUD from './components/HUD';
import StartScreen from './components/StartScreen';
import UpgradeModal from './components/UpgradeModal';
import GameOverScreen from './components/GameOverScreen';
import VictoryScreen from './components/VictoryScreen';

function App() {
  const initialized = useRef(false);
  const status = useGameStore((state) => state.status);
  const { setStatus, resetGame } = useGameStore();

  useEffect(() => {
    if (initialized.current) return;
    initialized.current = true;

    const game = createGame();

    return () => {
      game.destroy(true);
      initialized.current = false;
    };
  }, []);

  useEffect(() => {
    // 注册全局游戏事件的监听，方便与 Zustand / React 通信
    const onGameOver = () => setStatus('gameover');
    const onVictory = () => setStatus('victory');
    const onRestart = () => {
      resetGame();
      EventBus.emit(GameEvents.START_GAME);
    };

    EventBus.on(GameEvents.GAME_OVER, onGameOver);
    EventBus.on(GameEvents.VICTORY, onVictory);
    EventBus.on(GameEvents.RESTART_GAME, onRestart);

    return () => {
      EventBus.off(GameEvents.GAME_OVER, onGameOver);
      EventBus.off(GameEvents.VICTORY, onVictory);
      EventBus.off(GameEvents.RESTART_GAME, onRestart);
    };
  }, [setStatus, resetGame]);

  return (
    <div className="relative w-screen h-screen overflow-hidden bg-[#FDFBF7] select-none">
      {/* Phaser Canvas Container */}
      <div id="game-container" className="w-full h-full" />

      {/* UI Layers overlay */}
      {status === 'menu' && <StartScreen />}
      {status === 'playing' && <HUD />}
      {status === 'upgrading' && <UpgradeModal />}
      {status === 'gameover' && <GameOverScreen />}
      {status === 'victory' && <VictoryScreen />}
    </div>
  );
}

export default App;

